<?php include __DIR__ . '/../../includes/header.php'; require_permission('visitantes.crear');
$id=$_GET['id']??null; $row=['nombres'=>'','documento'=>'','empresa'=>'','motivo_visita'=>'','persona_visitada'=>'','fecha_visita'=>date('Y-m-d'),'estado_autorizacion'=>'PENDIENTE','qr_generado'=>''];
if($id){$st=$pdo->prepare("SELECT * FROM visitantes WHERE id_visitante=?");$st->execute([$id]);$row=$st->fetch();}
if($_SERVER['REQUEST_METHOD']==='POST'){ $qr=$_POST['qr_generado'] ?: generate_qr_token('VIS'); if($id){$pdo->prepare("UPDATE visitantes SET nombres=?,documento=?,empresa=?,motivo_visita=?,persona_visitada=?,fecha_visita=?,estado_autorizacion=?,qr_generado=? WHERE id_visitante=?")->execute([$_POST['nombres'],$_POST['documento'],$_POST['empresa'],$_POST['motivo_visita'],$_POST['persona_visitada'],$_POST['fecha_visita'],$_POST['estado_autorizacion'],$qr,$id]);} else {$pdo->prepare("INSERT INTO visitantes(nombres,documento,empresa,motivo_visita,persona_visitada,fecha_visita,estado_autorizacion,qr_generado) VALUES(?,?,?,?,?,?,?,?)")->execute([$_POST['nombres'],$_POST['documento'],$_POST['empresa'],$_POST['motivo_visita'],$_POST['persona_visitada'],$_POST['fecha_visita'],$_POST['estado_autorizacion'],$qr]);} log_event('GUARDAR_VISITANTE',$_POST['nombres']); flash('success','Visitante guardado.'); redirect('index.php');} ?>
<h1><?= $id?'Editar':'Nuevo' ?> visitante</h1><div class="card"><form method="POST" class="two-col"><div><label>Nombres</label><input name="nombres" value="<?= e($row['nombres']) ?>" required></div><div><label>Documento</label><input name="documento" value="<?= e($row['documento']) ?>" required></div><div><label>Empresa</label><input name="empresa" value="<?= e($row['empresa']) ?>"></div><div><label>Persona visitada</label><input name="persona_visitada" value="<?= e($row['persona_visitada']) ?>"></div><div><label>Fecha</label><input type="date" name="fecha_visita" value="<?= e($row['fecha_visita']) ?>"></div><div><label>Estado</label><select name="estado_autorizacion"><option>PENDIENTE</option><option <?= $row['estado_autorizacion']=='APROBADO'?'selected':'' ?>>APROBADO</option><option <?= $row['estado_autorizacion']=='RECHAZADO'?'selected':'' ?>>RECHAZADO</option></select></div><div style="grid-column:1/3"><label>Motivo</label><textarea name="motivo_visita"><?= e($row['motivo_visita']) ?></textarea></div><input type="hidden" name="qr_generado" value="<?= e($row['qr_generado']) ?>"><div><button>Guardar</button> <a class="btn btn-secondary" href="index.php">Volver</a></div></form></div><?php include __DIR__ . '/../../includes/footer.php'; ?>
